// Валидация + нормализация формы. Поддерживает оба тарифа: free и premium.
const input = $input.first().json;
const body = input.body || input;

const {
  tier = 'free',
  city = 'krym',
  days = 7,
  composition = 'couple',
  transport = 'car',
  budget = 5000,
  topic = 'obzor',
  notes = '',
  email = '',
  // premium-only поля (для free игнорируются)
  comfort = '',
  allergies = '',
  arrivalDate = '',
  departureDate = '',
  arrivalPoint = ''
} = body;

if (!email || !String(email).includes('@')) {
  throw new Error('Невалидный email: ' + email);
}

const tierNorm = tier === 'premium' ? 'premium' : 'free';
const nDays = Math.max(1, Math.min(21, Number(days) || 7));

const cityNames = {
  krym: 'Весь Крым',
  yalta: 'Ялта и Южный берег Крыма',
  sevastopol: 'Севастополь',
  bahchisaray: 'Бахчисарай',
  feodosiya: 'Феодосия и Коктебель',
  evpatoriya: 'Евпатория и западный Крым'
};
const compNames = {
  couple: 'пара',
  'family-kids': 'семья с детьми',
  friends: 'друзья',
  solo: 'один',
  parents: 'с родителями'
};
const transportNames = {
  car: 'на автомобиле',
  public: 'общественный транспорт (троллейбус №52, маршрутки, автобусы)',
  taxi: 'такси и трансферы',
  mixed: 'комбинированно (поезд/самолёт + такси)'
};
const topicNames = {
  obzor: 'обзорный — главные места',
  'more-plyazh': 'море и пляжи',
  gory: 'горы и треккинг',
  istoriya: 'история и архитектура',
  gastro: 'гастро и виноделие',
  's-detmi': 'с детьми',
  aktiv: 'активный отдых'
};
const comfortNames = {
  '': '',
  hostel: 'хостел или гестхаус (бюджетно)',
  econom: 'эконом 3*',
  comfort: 'комфорт 4*',
  premium: 'премиум 5*+ или бутик'
};
const arrivalPointNames = {
  '': '',
  simferopol: 'аэропорт Симферополь',
  anapa: 'аэропорт Анапа (~3-4 ч до Крыма через мост)',
  krasnodar: 'аэропорт Краснодар (~5 ч до Крыма)',
  'own-car': 'на собственном автомобиле через Крымский мост',
  train: 'поезд (станция Симферополь / Севастополь / Феодосия)'
};

const budgetNum = Number(budget);
const budgetText = budgetNum >= 999999
  ? 'без ограничений'
  : `до ${budgetNum.toLocaleString('ru-RU')} ₽ на чел/день`;

return [{
  json: {
    tier: tierNorm,
    city,
    days: nDays,
    composition,
    transport,
    budget: budgetNum,
    topic,
    notes: String(notes).slice(0, 500),
    email,
    cityName: cityNames[city] || cityNames.krym,
    compName: compNames[composition] || compNames.couple,
    transportName: transportNames[transport] || transportNames.car,
    topicName: topicNames[topic] || topicNames.obzor,
    budgetText,
    // premium-only — заполняются только если tier=premium
    comfort: tierNorm === 'premium' ? String(comfort) : '',
    comfortName: tierNorm === 'premium' ? (comfortNames[comfort] || '') : '',
    allergies: tierNorm === 'premium' ? String(allergies).slice(0, 300) : '',
    arrivalDate: tierNorm === 'premium' ? String(arrivalDate) : '',
    departureDate: tierNorm === 'premium' ? String(departureDate) : '',
    arrivalPoint: tierNorm === 'premium' ? String(arrivalPoint) : '',
    arrivalPointName: tierNorm === 'premium' ? (arrivalPointNames[arrivalPoint] || '') : ''
  }
}];

// Tier-aware промпт для OpenAI. Для free — компактный; для premium — расширенный
// с адресами, ресторанами, чек-листом и планом Б.
const m = $input.first().json;

const baseHeader = `Составь маршрут по Крыму на ${m.days} дней.

**Параметры**:
- Регион: ${m.cityName}
- Длительность: ${m.days} дней
- Состав: ${m.compName}
- Транспорт: ${m.transportName}
- Бюджет: ${m.budgetText}
- Главный интерес: ${m.topicName}
- Особые пожелания: ${m.notes || 'нет'}`;

let userPrompt;
let systemPrompt;
let maxTokens;

if (m.tier === 'premium') {
  const premiumExtras = [
    m.comfortName ? `- Уровень проживания: ${m.comfortName}` : null,
    m.arrivalPointName ? `- Прибытие через: ${m.arrivalPointName}` : null,
    m.arrivalDate ? `- Дата прибытия: ${m.arrivalDate}` : null,
    m.departureDate ? `- Дата отъезда: ${m.departureDate}` : null,
    m.allergies ? `- Аллергии и ограничения: ${m.allergies}` : null
  ].filter(Boolean).join('
');

  const itemsPerDay = m.composition === 'family-kids' ? '5-6' : '6-8';

  userPrompt = `${baseHeader}
${premiumExtras ? '
**Дополнительно (премиум)**:
' + premiumExtras + '
' : ''}
**Премиум-требования**:
1. Каждый день — ${itemsPerDay} точек с тайм-слотами (09:00, 11:30, 13:30, 16:00, 18:30, 20:30…).
2. У каждой точки указывай реальный адрес (улица, дом, город) и время в пути от предыдущей точки.
3. Минимум 2 ресторана/кафе в день — реальные, с адресами, кухней и ориентировочным средним чеком.
4. ${m.allergies ? 'Учитывай ограничения по питанию (см. выше).' : 'Делай упор на местную кухню (чебуреки, янтыки, татарский суп, шашлыки, плов, янтарное вино).'}
5. На каждый день — план Б на дождь / закрытие объекта (1-2 альтернативы).
6. ${m.arrivalPointName ? 'Учитывай точку прибытия (см. выше) и время в пути до Крыма.' : 'Финальный day = возврат в Симферополь.'}
7. Все объекты должны реально существовать в Крыму. Если не уверен — опускаешь.

Верни СТРОГО JSON по премиум-схеме (без markdown-обёртки, без комментариев).`;

  systemPrompt = `Ты — редактор премиум-путеводителя по Крыму с 10+ летним опытом и личным знанием региона. Составляешь подробные маршруты с конкретными местами, тайм-слотами, реальными адресами, временем в пути, гастрономическими подсказками. НИКОГДА не выдумываешь объекты, цены и расписания — если не уверен, опускаешь деталь. Стиль: лаконичный, на русском, с акцентом на гастрономию и логистику.

ВСЕГДА отвечаешь СТРОГО валидным JSON-объектом по премиум-схеме:
{
  "title": "короткий заголовок маршрута",
  "summary": "общее описание (3-4 предложения)",
  "total_km": число (приблизительный пробег, 0 если без авто),
  "days": [
    {
      "day": 1,
      "title": "Заголовок дня (откуда → куда)",
      "items": [
        {"time": "09:00", "place": "Название", "address": "Улица, д., город", "travel": "5 мин пешком от …", "note": "что делать / что попробовать"}
      ],
      "restaurants": [
        {"name": "Название", "address": "адрес", "cuisine": "крымско-татарская/европейская/etc", "price_avg": "≈800₽/чел", "why": "за что любим"}
      ],
      "rainy_alternative": "1-2 альтернативы на случай дождя"
    }
  ],
  "tips": ["совет 1", "совет 2", "совет 3"],
  "checklist": ["что взять в дорогу 1", "пункт 2", "пункт 3"],
  "budget_estimate": "строка с прикидкой бюджета на всю поездку"
}`;

  maxTokens = 4000;
} else {
  const itemsPerDay = m.composition === 'family-kids' ? '3-4' : '4-6';

  userPrompt = `${baseHeader}

**Требования**:
1. Каждый день — это ${itemsPerDay} точек с тайм-слотами (09:00, 12:00, и т.д.)
2. Учитывай переезды и пробки в сезон (особенно ЮБК)
3. Включи минимум 2 совета по гастрономии (где обедать, какие блюда местные)
4. Если транспорт = общественный — используй троллейбус №52 Симферополь—Ялта, маршрутки
5. Все объекты должны реально существовать в Крыму. Если не уверен — пропусти.
6. Финальный day обычно — возврат в Симферополь (откуда вылет/выезд)

Верни СТРОГО JSON по схеме (без markdown-обёртки, без комментариев).`;

  systemPrompt = `Ты — редактор путеводителя по Крыму с многолетним опытом. Составляешь практичные маршруты с конкретными местами, тайм-слотами, реальными адресами. НИКОГДА не выдумываешь объекты, цены и расписания — если не уверен, опускаешь деталь. Стиль: лаконичный, на русском, с гастрономическими и логистическими подсказками. ВСЕГДА отвечаешь СТРОГО валидным JSON-объектом по схеме:
{
  "title": "короткий заголовок маршрута",
  "summary": "параграф с общим описанием маршрута (2-3 предложения)",
  "total_km": число (приблизительный пробег, 0 если без авто),
  "days": [
    {"day": 1, "title": "Заголовок дня (откуда → куда)", "items": ["09:00 — действие/место с пояснением", "12:00 — ..."]}
  ],
  "tips": ["совет 1", "совет 2"],
  "budget_estimate": "строка с прикидкой бюджета на всю поездку"
}`;

  maxTokens = 2500;
}

return [{ json: { ...m, userPrompt, systemPrompt, maxTokens } }];

// Парсим ответ OpenAI и рендерим красивый HTML email.
// Tier-aware: для premium показываем рестораны, план Б, чек-лист и адреса.
const openaiRaw = $input.first().json;
const content = openaiRaw.choices?.[0]?.message?.content || '{}';

let plan;
try {
  plan = JSON.parse(content);
} catch (e) {
  const m = content.match(/\{[\s\S]+\}/);
  plan = m ? JSON.parse(m[0]) : { title: 'Ошибка', summary: 'Не удалось распарсить ответ AI', days: [], tips: [], budget_estimate: '' };
}

const meta = $('Validate & Normalize').first().json;
const isPremium = meta.tier === 'premium';

const esc = (s) => String(s ?? '').replace(/[&<>"']/g, (c) => ({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;' }[c]));

// Item рендер. Поддерживает строковый формат (free) и объектный (premium).
function renderItem(item) {
  if (typeof item === 'string') {
    return `<li style="padding: 6px 0 6px 18px; position: relative;"><span style="position:absolute; left:0; color:#7A1F2B;">·</span>${esc(item)}</li>`;
  }
  const time = esc(item.time || '');
  const place = esc(item.place || '');
  const meta2 = [item.address, item.travel].filter(Boolean).map(esc).join(' · ');
  const metaLine = meta2 ? `<div style=\"font-size:13px; color:#6b6b6b; margin-top:2px;\">${meta2}</div>` : '';
  const note = item.note ? `<div style=\"font-size:14px; color:#2a2a2a; margin-top:4px;\">${esc(item.note)}</div>` : '';
  return `<li style="padding: 10px 0 10px 18px; position: relative; border-top: 1px dashed #e6e2d8;">
    <span style="position:absolute; left:0; color:#7A1F2B;">·</span>
    <strong style="font-family: Georgia, serif;">${time ? time + ' — ' : ''}${place}</strong>${metaLine}${note}
  </li>`;
}

const dayBlocks = (plan.days || []).map((d) => {
  const items = (d.items || []).map(renderItem).join('');
  const restaurants = isPremium && Array.isArray(d.restaurants) && d.restaurants.length
    ? `<div style="margin: 12px 0 0; padding: 12px 14px; background:#FAF6EE; border-left:3px solid #7A1F2B;">
        <span style="display:block; font-family: Georgia, serif; font-size:12px; letter-spacing:0.16em; text-transform:uppercase; color:#7A1F2B; font-weight:600;">Рестораны и кафе</span>
        <ul style="margin:8px 0 0; padding-left: 18px; color:#2a2a2a; font-size:14px; line-height:1.55;">
          ${d.restaurants.map(r => {
            const meta3 = [r.address, r.cuisine, r.price_avg].filter(Boolean).map(esc).join(' · ');
            const why = r.why ? `<br/><span style=\\\"color:#6b6b6b;\\\">${esc(r.why)}</span>` : '';
            return `<li><strong>${esc(r.name)}</strong>${meta3 ? ' — ' + meta3 : ''}${why}</li>`;
          }).join('')}
        </ul>
      </div>`
    : '';
  const rainy = isPremium && d.rainy_alternative
    ? `<div style="margin: 12px 0 0; padding: 10px 14px; background: #f3f1eb; border-radius: 4px; font-size: 13px; color: #4a4a4a;"><strong>План Б на дождь:</strong> ${esc(d.rainy_alternative)}</div>`
    : '';
  return `
  <tr><td style="padding: 24px 0 8px; border-top: 1px solid #e6e2d8;">
    <span style="display:inline-block; font-family: Georgia, serif; font-size: 14px; color: #7A1F2B; letter-spacing: 0.1em; font-weight: 600;">ДЕНЬ ${esc(d.day)}</span>
    <h3 style="margin: 4px 0 16px; font-family: Georgia, serif; font-size: 22px; font-style: italic; font-weight: 400; color: #0E1B3A; line-height: 1.25;">${esc(d.title)}</h3>
    <ul style="margin: 0; padding: 0 0 0 4px; list-style: none; color: #2a2a2a; font-size: 15px; line-height: 1.6;">${items}</ul>
    ${restaurants}
    ${rainy}
  </td></tr>`;
}).join('');

const tipsBlock = (plan.tips || []).length
  ? `<tr><td style="padding: 24px 0; border-top: 1px solid #e6e2d8;">
      <span style="display:inline-block; font-family: Georgia, serif; font-size: 12px; color: #7A1F2B; letter-spacing: 0.16em; text-transform:uppercase; font-weight:600;">Советы</span>
      <ul style="margin: 12px 0 0 0; padding-left: 20px; color: #2a2a2a; font-size: 15px; line-height: 1.6;">
        ${plan.tips.map(t => `<li>${esc(t)}</li>`).join('')}
      </ul>
    </td></tr>`
  : '';

const checklistBlock = isPremium && Array.isArray(plan.checklist) && plan.checklist.length
  ? `<tr><td style="padding: 24px 0; border-top: 1px solid #e6e2d8;">
      <span style="display:inline-block; font-family: Georgia, serif; font-size: 12px; color: #7A1F2B; letter-spacing: 0.16em; text-transform:uppercase; font-weight:600;">Чек-лист в дорогу</span>
      <ul style="margin: 12px 0 0 0; padding-left: 20px; color: #2a2a2a; font-size: 15px; line-height: 1.6;">
        ${plan.checklist.map(c => `<li>${esc(c)}</li>`).join('')}
      </ul>
    </td></tr>`
  : '';

const budgetBlock = plan.budget_estimate
  ? `<tr><td style="padding: 16px 0; border-top: 1px solid #e6e2d8; font-size: 14px; color: #4a4a4a;"><strong>Бюджет:</strong> ${esc(plan.budget_estimate)}</td></tr>`
  : '';

const tierBadge = isPremium
  ? `<div style="display:inline-block; padding:5px 12px; background:#7A1F2B; color:#FAF6EE; font-family: Inter, Helvetica, Arial, sans-serif; font-size:11px; letter-spacing:0.18em; text-transform:uppercase; border-radius:2px; margin-bottom:16px;">Премиум · бесплатно в бета-периоде</div>`
  : '';

const subject = (isPremium ? '✦ Премиум-маршрут: ' : 'Ваш маршрут: ') + (plan.title || 'Крым');

const html = `<!DOCTYPE html><html lang="ru"><head><meta charset="UTF-8"><title>${esc(plan.title)}</title></head>
<body style="margin:0; padding:0; background:#FAF6EE; font-family: Helvetica, Arial, sans-serif; color: #1A1A1A;">
<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#FAF6EE; padding: 32px 16px;">
  <tr><td align="center">
    <table role="presentation" width="600" cellpadding="0" cellspacing="0" border="0" style="background:#FFFFFF; max-width: 600px; padding: 40px 32px;">
      <tr><td>
        ${tierBadge}
        <h1 style="font-family: Georgia, serif; font-size: 30px; font-weight: 500; line-height: 1.2; margin: 0 0 16px; color: #0E1B3A;">${esc(plan.title || 'Маршрут по Крыму')}</h1>
        <p style="font-family: Georgia, serif; font-style: italic; font-size: 18px; line-height: 1.55; color: #4a4a4a; margin: 0 0 8px;">${esc(plan.summary || '')}</p>
        ${plan.total_km ? `<p style=\"font-size: 14px; color: #6b6b6b; margin: 0 0 24px;\">Примерный пробег: <strong>${esc(plan.total_km)} км</strong></p>` : ''}
      </td></tr>
      ${dayBlocks}
      ${tipsBlock}
      ${checklistBlock}
      ${budgetBlock}
      <tr><td style="padding: 32px 0 0; font-size: 12px; color: #6b6b6b; line-height: 1.5; text-align: center; border-top: 1px solid #e6e2d8; margin-top: 32px;">
        Маршрут составлен AI на основе ваших ответов. Перепроверяйте часы работы и наличие мест перед поездкой.<br/>
        <a href="https://welcomecrimea.ru/" style="color: #7A1F2B;">welcomecrimea.ru</a>
      </td></tr>
    </table>
  </td></tr>
</table></body></html>`;

return [{ json: { html, subject, plan, tier: meta.tier } }];
